const now = new Date();
const month = now.getMonth() + 1;
const MONTHS = [
  { name: 'January',   season: 'Winter',        tip: 'Avoid walking on frozen grass. Plan spring care now.',                    upsell: 'Snow Removal' },
  { name: 'February',  season: 'Late Winter',    tip: 'Test soil pH before the thaw. Start planning spring cleanup.',             upsell: 'Spring Cleanup' },
  { name: 'March',     season: 'Early Spring',   tip: 'Time for spring cleanup! Remove debris before new growth.',                upsell: 'Fertilization' },
  { name: 'April',     season: 'Spring',         tip: 'Mow at 3-3.5 inches. Apply pre-emergent before soil hits 55F.',          upsell: 'Herbicide Services' },
  { name: 'May',       season: 'Late Spring',    tip: 'May is peak mulching season. Edge beds for a crisp, polished look.',      upsell: 'Mulching' },
  { name: 'June',      season: 'Early Summer',   tip: 'Raise mower to 4 inches. Mulch beds to retain moisture.',                 upsell: 'Mulching' },
  { name: 'July',      season: 'Summer',         tip: 'Water deeply 2-3x/week, early morning only. Watch for brown patch.',      upsell: 'Fertilization' },
  { name: 'August',    season: 'Late Summer',    tip: 'Book September aeration now. Start reducing watering frequency.',         upsell: 'Aeration' },
  { name: 'September', season: 'Early Fall',     tip: 'Fall is BEST time to fertilize. Cool nights + warm soil.',                upsell: 'Fall Fertilization' },
  { name: 'October',   season: 'Fall',           tip: 'Lower final mow height to 2.5 inches. Remove leaves weekly.',            upsell: 'Leaf Removal' },
  { name: 'November',  season: 'Late Fall',      tip: 'Final leaf cleanup before snow. Consider gutter guards.',                 upsell: 'Gutter Cleaning' },
  { name: 'December',  season: 'Early Winter',   tip: 'Avoid salt damage to lawn edges. Rest your lawn.',                        upsell: 'Snow Removal' }
];
const m = MONTHS[month - 1];
return [{ json: { monthName: m.name, season: m.season, tip: m.tip, upsell: m.upsell, month } }];

const ctx = $('Determine Month Context').first().json;
const reviews = $('Fetch 5-Star Review').all().map(i => i.json);
const customers = $('Fetch Active Customers').all().map(i => i.json);

const review = reviews[0] || { author_name: 'A Happy Customer', review_text: 'TotalGuard does amazing work. Highly recommend!' };

const FONT = "-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,sans-serif";
const GREEN = '#2D5A27';
const GOLD = '#C5A55A';
const DARK = '#1a1a2e';

function buildNewsletter(firstName) {
  return `<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"></head><body style="margin:0;padding:0;background:#f4f4f4;font-family:${FONT};">
<table width="100%" cellpadding="0" cellspacing="0" style="background:#f4f4f4;"><tr><td align="center" style="padding:20px 0;">
<table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;background:#fff;border-radius:8px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.06);">
<!-- Header -->
<tr><td style="background:${GREEN};padding:16px 24px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td style="font-size:18px;font-weight:700;color:#fff;">TotalGuard Yard Care</td><td align="right" style="font-size:14px;"><a href="tel:+16085356057" style="color:#fff;text-decoration:none;font-weight:600;">(608) 535-6057</a></td></tr><tr><td colspan="2" align="center" style="padding-top:8px;font-size:12px;color:${GOLD};letter-spacing:1.5px;text-transform:uppercase;font-weight:600;">Madison's Most Trusted Yard Care</td></tr></table></td></tr>
<!-- Hero -->
<tr><td style="background:linear-gradient(135deg,${GREEN} 0%,#3d7a34 50%,${GREEN} 100%);padding:40px 32px;text-align:center;"><h1 style="margin:0;font-size:26px;font-weight:800;color:#fff;line-height:1.2;">${ctx.monthName} Yard Report</h1><p style="margin:12px 0 0;font-size:15px;color:${GOLD};font-weight:500;">${ctx.season} Edition &mdash; Tips for Madison Homeowners</p></td></tr>
<!-- Seasonal Tip -->
<tr><td style="padding:32px 32px 16px;"><h2 style="margin:0 0 12px;font-size:18px;color:${GREEN};">&#127793; Seasonal Tip</h2><p style="margin:0;font-size:15px;color:#333;line-height:1.7;">Hi ${firstName} &mdash; ${ctx.tip}</p></td></tr>
<!-- Featured Service -->
<tr><td style="padding:16px 32px;"><table width="100%" cellpadding="0" cellspacing="0" style="background:#f0f8f0;border:2px solid ${GREEN};border-radius:8px;"><tr><td style="padding:20px 24px;"><p style="margin:0 0 8px;font-size:16px;font-weight:700;color:${GREEN};">&#11088; Featured Service: ${ctx.upsell}</p><p style="margin:0 0 16px;font-size:14px;color:#333;line-height:1.6;">This ${ctx.season.toLowerCase()} season is the perfect time to add ${ctx.upsell.toLowerCase()} to your yard care plan. Ask us for a free estimate!</p><table cellpadding="0" cellspacing="0" style="width:100%;"><tr><td align="center" style="border-radius:6px;background:${GREEN};"><a href="https://tgyardcare.com/contact?utm_source=email&utm_medium=newsletter&utm_campaign=yard-report-${ctx.monthName.toLowerCase()}" style="display:block;padding:14px 28px;font-size:15px;font-weight:700;color:#fff;text-decoration:none;border-radius:6px;text-align:center;">Get a Free Estimate</a></td></tr></table></td></tr></table></td></tr>
<!-- Review Spotlight -->
<tr><td style="padding:16px 32px;"><h2 style="margin:0 0 12px;font-size:18px;color:${GREEN};">&#11088; Review Spotlight</h2><table width="100%" cellpadding="0" cellspacing="0" style="background:#f9f9f9;border-radius:8px;"><tr><td style="padding:20px 24px;"><div style="color:${GOLD};font-size:20px;letter-spacing:2px;">&#9733;&#9733;&#9733;&#9733;&#9733;</div><p style="margin:12px 0 8px;font-style:italic;font-size:14px;color:#333;line-height:1.6;">&ldquo;${review.review_text}&rdquo;</p><p style="margin:0;font-size:13px;font-weight:700;color:#1a1a1a;">&mdash; ${review.author_name}</p></td></tr></table></td></tr>
<!-- CTA -->
<tr><td style="padding:24px 32px;" align="center"><table cellpadding="0" cellspacing="0" style="width:100%;"><tr><td align="center" style="border-radius:6px;background:${GREEN};"><a href="https://tgyardcare.com/contact?utm_source=email&utm_medium=newsletter&utm_campaign=yard-report-${ctx.monthName.toLowerCase()}" style="display:block;padding:16px 32px;font-size:16px;font-weight:700;color:#fff;text-decoration:none;border-radius:6px;text-align:center;">Schedule Your Next Service</a></td></tr></table></td></tr>
<!-- Trust Bar -->
<tr><td style="padding:0 32px 24px;"><table width="100%" cellpadding="0" cellspacing="0" style="background:${GREEN};border-radius:6px;"><tr><td align="center" style="padding:14px 16px;font-size:12px;color:#fff;line-height:2;">&#10003; Licensed &amp; Insured &bull; &#10003; 4.9&#9733; Rating &bull; &#10003; 500+ Properties &bull; &#10003; Satisfaction Guarantee</td></tr></table></td></tr>
<!-- Footer -->
<tr><td style="background:${DARK};border-radius:0 0 8px 8px;padding:24px 32px;text-align:center;"><p style="margin:0 0 8px;font-size:16px;font-weight:700;color:#fff;">TotalGuard Yard Care</p><p style="margin:0 0 8px;font-size:13px;color:#999;">7610 Welton Dr, Madison, WI 53711 &bull; <a href="tel:+16085356057" style="color:${GOLD};text-decoration:none;">(608) 535-6057</a> &bull; <a href="mailto:totalguardllc@gmail.com" style="color:${GOLD};text-decoration:none;">totalguardllc@gmail.com</a></p><p style="margin:8px 0 0;font-size:11px;color:#666;">You're receiving this because you're a TotalGuard customer. <a href="https://tgyardcare.com/unsubscribe" style="color:#999;text-decoration:underline;">Unsubscribe</a></p></td></tr>
</table></td></tr></table></body></html>`;
}

const results = [];
for (const c of customers) {
  if (!c.email) continue;
  const firstName = c.first_name || 'there';
  const subject = `${ctx.monthName} Yard Report from TotalGuard`;
  const html_body = buildNewsletter(firstName);

  results.push({
    json: {
      to_email: c.email,
      subject: subject,
      html_body: html_body,
      workflow_name: 'TG-81',
      email_type: 'monthly_newsletter'
    }
  });
}

return results.length > 0 ? results : [{ json: { _skip: true, reason: 'No customers found' } }];

